<script setup>
import { computed, defineProps } from 'vue'

const props = defineProps({
	value: String,
})

const humidity = computed(() => {
	const match = props.value.match(/(\d+)/)
	return match ? parseFloat(match[1]) : 0
})

const humidityFillPath = computed(() => {
	const h = humidity.value

	const keyframes = [
		{
			percent: 0,
			y: 198.56743,
			c1_y: 0.0188,
			c1_x: -13.535195,
			c2_y: 0.0233,
			c2_x: -15.482683,
			h_vert: 0.27784,
			curve_c1: 1.84483,
			curve_c2: 2.2864,
			c_y2: 0.0805,
			c_y3: 0.0422,
			v_height: 0.27784
		},
		{
			percent: 50,
			y: 168.96225,
			c1_y: 1.84483,
			c1_x: -13.532495,
			c2_y: 2.2864,
			c2_x: -15.479595,
			h_vert: 27.26419,
			curve_c1: 1.84483,
			curve_c2: 2.2864,
			c_y2: 0.0805,
			c_y3: 0.0422,
			v_height: 27.26419
		},
		{
			percent: 100,
			y: 129.09127,
			c1_y: 4.31375,
			c1_x: -13.519335,
			c2_y: 5.34627,
			c2_x: -15.464542,
			h_vert: 63.7516,
			curve_c1: 4.31375,
			curve_c2: 5.34627,
			c_y2: 0.18824,
			c_y3: 0.0987,
			v_height: 63.7516
		}
	]

	const lerp = (a, b, t) => a + (b - a) * t

	let frameA, frameB, t

	if (h <= 50) {
		frameA = keyframes[0]
		frameB = keyframes[1]
		t = h / 50
	} else {
		frameA = keyframes[1]
		frameB = keyframes[2]
		t = (h - 50) / 50
	}

	const interpY = lerp(frameA.y, frameB.y, t)
	const interp_c1_y = lerp(frameA.c1_y, frameB.c1_y, t)
	const interp_c2_y = lerp(frameA.c2_y, frameB.c2_y, t)
	const interp_v_height = lerp(frameA.v_height, frameB.v_height, t)
	const interp_c_y2 = lerp(frameA.c_y2, frameB.c_y2, t)
	const interp_c_y3 = lerp(frameA.c_y3, frameB.c_y3, t)

	return `m 76.3,${interpY.toFixed(5)}
c -5.02,0 -13.53,${interp_c1_y.toFixed(5)} -15.48,${interp_c2_y.toFixed(5)}
l -.375,.002
v ${interp_c_y2.toFixed(4)}
c -.1226,${interp_c_y3.toFixed(4)} -.1878,${interp_c_y3.toFixed(4)} -.1878,${interp_c_y3.toFixed(4)}
h .1878
v ${interp_v_height.toFixed(5)}
H 181.60894
v -${interp_v_height.toFixed(5)}
h .19862
c 0,0 -.0692,-.0196 -.19862,-.054
v -.39252
