c -2.64437,-.58878 -8.48127,-2.02146 -12.80498,-2.02146 -5.68044,0 -10.20567,1.16774 -15.88613,1.16774 -5.68047,0 -8.82099,-1.16774 -14.50134,-1.16774 -5.68037,0 -10.2051,1.16774 -15.88547,1.16774 -5.68034,0 -8.82106,-1.16774 -14.50142,-1.16774 -5.68037,0 -10.20559,1.16774 -15.886052,1.16774 -5.68046,0 -8.820973,-1.16774 -14.501334,-1.16774
